class Solution {
public:
    std::string removeDuplicates(std::string s) {
        if (s.size() <= 1) return s;
        std::string res = \"\";
        for (char ch : s) {
            if (res.size() && res.back() != ch) res.push_back(ch);
        }
        return res;
    }
};

